func idna15Allows(character rune) bool {
	value := uint32(character)
	low, high := 0, len(idna15AllowedRanges)
	for low < high {
		middle := low + (high-low)/2
		entry := idna15AllowedRanges[middle]
		start, end := uint32(entry>>32), uint32(entry)
		switch {
		case value < start:
			high = middle
		case value >= end:
			low = middle + 1
		default:
			return true
		}
	}
	return false
}
